import{_ as s,o as i,c as t,ak as e}from"./chunks/framework.DwHlt8HN.js";const c=JSON.parse('{"title":"索引基础","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/optimize/index/basic.md","filePath":"mysql/optimize/index/basic.md","lastUpdated":1774248380000}'),l={name:"mysql/optimize/index/basic.md"};function n(r,a,h,d,p,k){return i(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="索引基础" tabindex="-1">索引基础 <a class="header-anchor" href="#索引基础" aria-label="Permalink to “索引基础”">​</a></h1><blockquote><p>没有索引的表，就像没有目录的书——你只能从第一页翻到最后一页来找一个词。</p></blockquote><hr><h2 id="索引是什么" tabindex="-1">索引是什么 <a class="header-anchor" href="#索引是什么" aria-label="Permalink to “索引是什么”">​</a></h2><p><strong>索引（Index）</strong> 是数据库中一种特殊的数据结构，用于加速数据检索。它类似于书籍的目录：你不需要逐页翻书，只需要看目录就能快速定位到目标内容。</p><p>在 MySQL 中，索引存储在独立的磁盘文件中（InnoDB 引擎下，索引和数据在同一个表空间文件），每个索引本质上是一棵 B+ 树。</p><h3 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h3><p>索引 = 排好序的查找数据结构，用空间换时间。</p><hr><h2 id="索引为什么快" tabindex="-1">索引为什么快 <a class="header-anchor" href="#索引为什么快" aria-label="Permalink to “索引为什么快”">​</a></h2><p>要理解索引为什么快，先看没有索引时数据库是怎么查数据的。</p><h3 id="全表扫描-逐行查找" tabindex="-1">全表扫描：逐行查找 <a class="header-anchor" href="#全表扫描-逐行查找" aria-label="Permalink to “全表扫描：逐行查找”">​</a></h3><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> customer_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10086</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>没有索引时，MySQL 从第一行开始，一条一条地比较 <code>customer_id</code> 的值，直到找到匹配的记录或者遍历完所有行。</p><p>100 万条数据？最坏情况要比较 100 万次。</p><h3 id="索引查找-二分定位" tabindex="-1">索引查找：二分定位 <a class="header-anchor" href="#索引查找-二分定位" aria-label="Permalink to “索引查找：二分定位”">​</a></h3><p>有了索引（假设是 B+ 树索引），查找过程是这样的：</p><ol><li>从根节点开始，判断目标值在左子树还是右子树</li><li>逐层向下，直到叶子节点</li><li>在叶子节点中通过双向链表快速定位</li></ol><p>100 万条数据，B+ 树高度约为 3~4 层，最多比较 3~4 次就能找到结果。</p><p>这就是索引快的本质：<strong>把全表扫描的 O(n) 降到了 O(log n)</strong>。</p><hr><h2 id="索引的优缺点" tabindex="-1">索引的优缺点 <a class="header-anchor" href="#索引的优缺点" aria-label="Permalink to “索引的优缺点”">​</a></h2><p>索引不是银弹，它有代价。</p><h3 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to “优点”">​</a></h3><table tabindex="0"><thead><tr><th>优点</th><th>说明</th></tr></thead><tbody><tr><td><strong>加速查询</strong></td><td>减少 I/O 次数，显著降低查询时间</td></tr><tr><td><strong>减少服务器扫描量</strong></td><td>不需要遍历全表</td></tr><tr><td><strong>实现唯一约束</strong></td><td>唯一索引保证数据唯一性</td></tr><tr><td><strong>支持排序和分组</strong></td><td>索引本身有序，减少 sort 操作</td></tr></tbody></table><h3 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to “缺点”">​</a></h3><table tabindex="0"><thead><tr><th>缺点</th><th>说明</th></tr></thead><tbody><tr><td><strong>占用磁盘空间</strong></td><td>索引文件可能比数据文件还大</td></tr><tr><td><strong>降低写操作性能</strong></td><td>INSERT/UPDATE/DELETE 时需要同步维护索引</td></tr><tr><td><strong>增加维护成本</strong></td><td>数据变更时，索引需要实时更新</td></tr><tr><td><strong>不是越多越好</strong></td><td>大量索引反而拖慢写入，浪费空间</td></tr></tbody></table><hr><h2 id="索引设计的基本原则" tabindex="-1">索引设计的基本原则 <a class="header-anchor" href="#索引设计的基本原则" aria-label="Permalink to “索引设计的基本原则”">​</a></h2><p>不是所有字段都值得建索引，设计索引需要权衡。</p><h3 id="适合建索引的字段" tabindex="-1">适合建索引的字段 <a class="header-anchor" href="#适合建索引的字段" aria-label="Permalink to “适合建索引的字段”">​</a></h3><ul><li>WHERE 子句中频繁使用的字段</li><li>JOIN 的 ON 条件涉及的字段</li><li>ORDER BY 和 GROUP BY 涉及的字段</li><li>区分度高的字段（ cardinality 高，如用户 ID）</li><li>很少更新的字段（索引维护成本低）</li></ul><h3 id="不适合建索引的字段" tabindex="-1">不适合建索引的字段 <a class="header-anchor" href="#不适合建索引的字段" aria-label="Permalink to “不适合建索引的字段”">​</a></h3><ul><li>区分度很低的字段（如性别：只有男/女，区分度 50%）</li><li>频繁更新的字段（每次更新都要维护索引）</li><li>非常长的字符串字段（用前缀索引除外）</li><li>查询中几乎不使用的字段（浪费空间）</li></ul><h3 id="索引设计经验法则" tabindex="-1">索引设计经验法则 <a class="header-anchor" href="#索引设计经验法则" aria-label="Permalink to “索引设计经验法则”">​</a></h3><blockquote><p><strong>经验法则</strong>：为 WHERE、ORDER BY、GROUP BY 涉及的字段建索引。</p></blockquote><p>一个经典的复合索引设计示例：</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 经常这样查询：</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> status</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;paid&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DESC</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 复合索引设计：</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> INDEX</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> idx_status_created</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DESC</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">--                    ↑ 等值查询放前  ↑ 排序字段紧随其后</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这个索引同时覆盖了 WHERE 条件（<code>status</code>）和排序（<code>created_at</code>），查询时可以直接从索引中返回结果，无需回表。</p><hr><h2 id="mysql-索引分类体系" tabindex="-1">MySQL 索引分类体系 <a class="header-anchor" href="#mysql-索引分类体系" aria-label="Permalink to “MySQL 索引分类体系”">​</a></h2><p>从逻辑上，MySQL 索引分为以下几类：</p><table tabindex="0"><thead><tr><th>分类角度</th><th>类型</th></tr></thead><tbody><tr><td>数据结构</td><td>B+ 树索引、Hash 索引、R-Tree 索引（空间数据）</td></tr><tr><td>物理存储</td><td>聚簇索引（主键索引）、二级索引（非主键索引）</td></tr><tr><td>字段个数</td><td>单列索引、联合索引（复合索引）</td></tr><tr><td>唯一性</td><td>唯一索引、普通索引</td></tr></tbody></table><blockquote><p>关于各种索引类型的详细讲解，参见 <a href="/database/mysql/optimize/index/type">索引类型：聚簇/二级/联合/B+树/Hash</a>。</p></blockquote><hr><h2 id="验证索引效果" tabindex="-1">验证索引效果 <a class="header-anchor" href="#验证索引效果" aria-label="Permalink to “验证索引效果”">​</a></h2><p>用 <code>EXPLAIN</code> 可以看到查询是否使用了索引：</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 查看查询计划</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">EXPLAIN </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> customer_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10086</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>关键字段说明：</p><table tabindex="0"><thead><tr><th>字段</th><th>值</th><th>含义</th></tr></thead><tbody><tr><td>type</td><td>ALL</td><td>全表扫描，慢</td></tr><tr><td>type</td><td>ref, range</td><td>索引扫描，快</td></tr><tr><td>key</td><td>idx_xxx</td><td>实际使用的索引名</td></tr><tr><td>rows</td><td>1000000</td><td>预计扫描行数</td></tr></tbody></table><blockquote><p>详细内容见 <a href="/database/mysql/optimize/tool/explain">EXPLAIN 全字段剖析</a>。</p></blockquote><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><p>索引是 MySQL 性能优化的核心。理解索引的原理和设计原则，比记住几条优化技巧更重要。</p><p>记住三句话：</p><ul><li><strong>索引用空间换时间</strong>：磁盘空间换查询速度</li><li><strong>索引是排好序的 B+ 树</strong>：有序才能二分查找</li><li><strong>索引不是越多越好</strong>：写入变慢，空间膨胀</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to “下一步”">​</a></h2><p>索引的底层数据结构是什么？聚簇索引和二级索引有什么区别？</p><p>从 <a href="/database/mysql/optimize/index/type">索引类型</a> 继续。</p>`,60)])])}const b=s(l,[["render",n]]);export{c as __pageData,b as default};
